import{_ as d,o as a,c as r,a0 as e}from"./chunks/framework.DTwdCQre.js";const m=JSON.parse('{"title":"Roadmap","description":"claude-code-Go 项目 Roadmap","frontmatter":{"title":"Roadmap","description":"claude-code-Go 项目 Roadmap"},"headers":[],"relativePath":"zh/roadmap.md","filePath":"zh/roadmap.md","lastUpdated":1777729439000}'),o={name:"zh/roadmap.md"};function l(i,t,n,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>以下是 claude-code-Go 的 Roadmap，分为三个阶段。</p><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>状态</th><th>描述</th></tr></thead><tbody><tr><td>第一阶段</td><td>✅ 已完成</td><td>核心基础 — Agent loop、工具、权限、SSE、会话</td></tr><tr><td>第二阶段</td><td>✅ 已完成</td><td>增强功能 — Skills、多 Provider、会话恢复</td></tr><tr><td>第三阶段</td><td>🟡 进行中</td><td>v0.3 扩展产品化 — MCP、LSP、Hooks、Skills、Replay evidence</td></tr></tbody></table><hr><h2 id="第一阶段-基础架构-✅-已完成" tabindex="-1">第一阶段：基础架构 ✅ 已完成 <a class="header-anchor" href="#第一阶段-基础架构-✅-已完成" aria-label="Permalink to &quot;第一阶段：基础架构 ✅ 已完成&quot;">​</a></h2><p>第一阶段建立了 AI 编程助手的核心基础设施。</p><h3 id="已完成功能" tabindex="-1">已完成功能 <a class="header-anchor" href="#已完成功能" aria-label="Permalink to &quot;已完成功能&quot;">​</a></h3><ul><li><strong>Agent Loop</strong> — 由 stop_reason 驱动的「思考→行动→观察」自主循环</li><li><strong>9 大内置工具</strong> — 6 个核心（Read、Write、Edit、Glob、Grep、Bash）+ 3 个增强（Diff view、Tree、WebFetch）</li><li><strong>权限系统</strong> — 三级权限模型，支持 glob 规则匹配与会话记忆</li><li><strong>MCP 集成</strong> — 当前为 v0.3 partial：配置、命名空间、权限门控和 harness 证据正在产品化</li><li><strong>SSE 流式</strong> — 逐 token 实时流式输出</li><li><strong>会话持久化</strong> — 保存和恢复对话状态</li><li><strong>Hooks 系统</strong> — 执行前后回调，扩展能力</li></ul><hr><h2 id="第二阶段-增强功能-✅-已完成" tabindex="-1">第二阶段：增强功能 ✅ 已完成 <a class="header-anchor" href="#第二阶段-增强功能-✅-已完成" aria-label="Permalink to &quot;第二阶段：增强功能 ✅ 已完成&quot;">​</a></h2><p>第二阶段添加了更强大的功能，提升可用性和灵活性。</p><h3 id="已完成功能-1" tabindex="-1">已完成功能 <a class="header-anchor" href="#已完成功能-1" aria-label="Permalink to &quot;已完成功能&quot;">​</a></h3><ul><li><strong>Skills 系统</strong> — 自定义命令和可重用工作流（如 <code>/review-pr</code>、<code>/deploy</code>）</li><li><strong>多 Provider 支持</strong> — Anthropic、OpenAI 及任何 OpenAI 兼容 API</li><li><strong>会话恢复</strong> — 加载之前的对话并无缝衔接</li><li><strong>增强工具</strong> — Diff 视图、树形可视化、网页抓取</li><li><strong>手动压缩</strong> — <code>/compact</code> 命令减少上下文大小</li><li><strong>自动更新</strong> — <code>/update</code> 命令检查版本并更新</li></ul><hr><h2 id="第三阶段-扩展产品化-🟡-进行中" tabindex="-1">第三阶段：扩展产品化 🟡 进行中 <a class="header-anchor" href="#第三阶段-扩展产品化-🟡-进行中" aria-label="Permalink to &quot;第三阶段：扩展产品化 🟡 进行中&quot;">​</a></h2><p>当前重点是把已有扩展代码变成可诊断、可验证、可文档化的产品能力。</p><h3 id="当前范围" tabindex="-1">当前范围 <a class="header-anchor" href="#当前范围" aria-label="Permalink to &quot;当前范围&quot;">​</a></h3><ul><li><strong>MCP 集成 (Partial v0.3)</strong> — 配置、工具命名空间、权限门控、文档和 harness 场景</li><li><strong>LSP 集成 (Partial v0.3)</strong> — 健康检查、能力门控、doctor 诊断、文档和 unavailable harness 场景</li><li><strong>Replay evidence</strong> — extension events、permission decisions、secret redaction 和 evidence mode</li><li><strong>Docs/PARITY 对齐</strong> — 中英文文档只声明已有证据支持的能力</li></ul><h3 id="愿景" tabindex="-1">愿景 <a class="header-anchor" href="#愿景" aria-label="Permalink to &quot;愿景&quot;">​</a></h3><p>第三阶段的目标是先稳定 CLI/TUI runtime 和扩展证据，再考虑 IDE、团队协作或云端能力。</p><hr><h2 id="参与贡献" tabindex="-1">参与贡献 <a class="header-anchor" href="#参与贡献" aria-label="Permalink to &quot;参与贡献&quot;">​</a></h2><p>想影响 Roadmap？查看 <a href="/claude-code-Go/zh/feedback.html">反馈</a> 页面了解如何提交问题报告和功能请求。</p><hr><h2 id="功能对比" tabindex="-1">功能对比 <a class="header-anchor" href="#功能对比" aria-label="Permalink to &quot;功能对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>Phase 1</th><th>Phase 2</th><th>Claude Code</th></tr></thead><tbody><tr><td>Agent Loop</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>内置工具</td><td>6 个核心</td><td>9 个</td><td>20+</td></tr><tr><td>权限系统</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>MCP 集成 (Partial v0.3)</td><td>🟡</td><td>🟡</td><td>✅</td></tr><tr><td>SSE 流式</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>会话持久化</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>会话恢复</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Skills 系统</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>多 Provider 支持</td><td>❌</td><td>✅</td><td>❌</td></tr><tr><td>自动更新</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Hooks 系统</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>运行时切换模型</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>IDE 集成</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><hr><p><em>最后更新：2026 年 5 月</em></p>',29)])])}const u=d(o,[["render",l]]);export{m as __pageData,u as default};
